
import {
    Switch,
    Route,
    BrowserRouter as Router,
    Link,
} from 'react-router-dom';
import React, { useState } from 'react';
import {
    routers,
} from './routes';
import { 
    Menu,
    Button,
} from 'antd';
import {
    AppstoreOutlined,
    MenuUnfoldOutlined,
    MenuFoldOutlined,
    PieChartOutlined,
    DesktopOutlined,
    ContainerOutlined,
    MailOutlined,
} from '@ant-design/icons';

import 'antd/dist/antd.css';
import Layout, { Content } from 'antd/lib/layout/layout';
import Sider from 'antd/lib/layout/Sider';
import { SIDEBAR_COLLAPSED } from './constants/key';

function App() {
    const [collapsed, setCollapsed] = useState(localStorage.getItem(SIDEBAR_COLLAPSED) === 'true');
    function toggleCollapsed() {
        setCollapsed(d => !d);
        localStorage.setItem(SIDEBAR_COLLAPSED, '' + !collapsed);
    }
    return (
        <Router>
            <Layout style={{height: '100vh'}}>
                <Sider collapsible collapsed={collapsed} onCollapse={toggleCollapsed}>
                    <Menu
                        defaultSelectedKeys={['0']}
                        mode="inline"
                        theme="dark"
                        inlineCollapsed={false}
                        >
                            {
                                routers.map((route, idx) => <Menu.Item key={route.path} icon={React.createElement(route.icon)}>
                                    <Link to={route.path}>{route.title}</Link>
                                </Menu.Item>)
                            }
                    </Menu>
                </Sider>
                <Content style={{flexGrow: 1, padding: 16}}>
                    <Switch>
                        {
                            routers.map(route => <Route key={route.path} children={route.page} path={route.path} />)
                        }
                    </Switch>
                </Content>
            </Layout>
        </Router>
    );
}

export default App;
